#!/usr/bin/env node
/**
 * Build script: reads all std/*.js files and writes editor/std-bundle.js
 * as an ESM map from path → source string.
 *
 * Run:  node editor/bundle-std.js
 */

import { readFileSync, readdirSync, writeFileSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const stdDir = join(__dirname, '..', 'std');
const outFile = join(__dirname, 'std-bundle.js');

const files = readdirSync(stdDir).filter(f => f.endsWith('.js'));
const map = {};

for (const file of files) {
  const key = `std/${file}`;
  map[key] = readFileSync(join(stdDir, file), 'utf-8');
}

const content = `// Auto-generated by editor/bundle-std.js — do not edit manually
export const STD_FILES = ${JSON.stringify(map, null, 2)};
`;

writeFileSync(outFile, content, 'utf-8');
console.log(`Wrote ${Object.keys(map).length} std files to editor/std-bundle.js`);
